import{_ as e,o as a,c as d,ag as s}from"./chunks/framework.BYYsWsaA.js";const o="/docs/images/budget-complete.png",g=JSON.parse('{"title":"Build a Budget Spreadsheet","description":"","frontmatter":{},"headers":[],"relativePath":"guide/build-a-budget.md","filePath":"guide/build-a-budget.md"}'),n={name:"guide/build-a-budget.md"};function r(l,t,i,u,h,p){return a(),d("div",null,[...t[0]||(t[0]=[s('<h1 id="build-a-budget-spreadsheet" tabindex="-1">Build a Budget Spreadsheet <a class="header-anchor" href="#build-a-budget-spreadsheet" aria-label="Permalink to &quot;Build a Budget Spreadsheet&quot;">​</a></h1><p>In this guide, you&#39;ll build a monthly budget tracker from scratch. Along the way, you&#39;ll learn how to use formulas, format numbers, and organize your data.</p><h2 id="_1-set-up-the-structure" tabindex="-1">1. Set Up the Structure <a class="header-anchor" href="#_1-set-up-the-structure" aria-label="Permalink to &quot;1. Set Up the Structure&quot;">​</a></h2><p>Create a new document and enter the following headers and data:</p><table tabindex="0"><thead><tr><th></th><th>A</th><th>B</th><th>C</th></tr></thead><tbody><tr><td>1</td><td><strong>Category</strong></td><td><strong>Budget</strong></td><td><strong>Actual</strong></td></tr><tr><td>2</td><td>Rent</td><td>1500</td><td>1500</td></tr><tr><td>3</td><td>Groceries</td><td>400</td><td>380</td></tr><tr><td>4</td><td>Transport</td><td>200</td><td>220</td></tr><tr><td>5</td><td>Utilities</td><td>150</td><td>135</td></tr><tr><td>6</td><td>Entertainment</td><td>100</td><td>95</td></tr><tr><td>7</td><td>Savings</td><td>500</td><td>500</td></tr></tbody></table><h2 id="_2-add-a-totals-row" tabindex="-1">2. Add a Totals Row <a class="header-anchor" href="#_2-add-a-totals-row" aria-label="Permalink to &quot;2. Add a Totals Row&quot;">​</a></h2><p>Click on cell <strong>A8</strong> and type <code>Total</code>. In <strong>B8</strong>, type a SUM formula to add up all budget amounts:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=SUM(B2:B7)</span></span></code></pre></div><p>Press <code>Enter</code>. The cell should display <strong>2850</strong>. Now do the same in <strong>C8</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=SUM(C2:C7)</span></span></code></pre></div><h2 id="_3-calculate-the-difference" tabindex="-1">3. Calculate the Difference <a class="header-anchor" href="#_3-calculate-the-difference" aria-label="Permalink to &quot;3. Calculate the Difference&quot;">​</a></h2><p>Add a <strong>Difference</strong> column to see if you&#39;re under or over budget. In <strong>D1</strong>, type <code>Difference</code>. In <strong>D2</strong>, enter:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=B2-C2</span></span></code></pre></div><p>This shows how much you saved (positive) or overspent (negative) for Rent. Now you need the same formula for every row.</p><h3 id="copy-a-formula-down" tabindex="-1">Copy a Formula Down <a class="header-anchor" href="#copy-a-formula-down" aria-label="Permalink to &quot;Copy a Formula Down&quot;">​</a></h3><ol><li>Select cell <strong>D2</strong></li><li>Drag the fill handle (the small square at the bottom-right corner of the cell) down to <strong>D8</strong></li><li>Each row now calculates its own difference — the cell references adjust automatically</li></ol><p>Your spreadsheet should now look like this:</p><table tabindex="0"><thead><tr><th></th><th>A</th><th>B</th><th>C</th><th>D</th></tr></thead><tbody><tr><td>1</td><td>Category</td><td>Budget</td><td>Actual</td><td>Difference</td></tr><tr><td>2</td><td>Rent</td><td>1500</td><td>1500</td><td>0</td></tr><tr><td>3</td><td>Groceries</td><td>400</td><td>380</td><td>20</td></tr><tr><td>4</td><td>Transport</td><td>200</td><td>220</td><td>-20</td></tr><tr><td>5</td><td>Utilities</td><td>150</td><td>135</td><td>15</td></tr><tr><td>6</td><td>Entertainment</td><td>100</td><td>95</td><td>5</td></tr><tr><td>7</td><td>Savings</td><td>500</td><td>500</td><td>0</td></tr><tr><td>8</td><td>Total</td><td>2850</td><td>2830</td><td>20</td></tr></tbody></table><h2 id="_4-use-conditional-logic" tabindex="-1">4. Use Conditional Logic <a class="header-anchor" href="#_4-use-conditional-logic" aria-label="Permalink to &quot;4. Use Conditional Logic&quot;">​</a></h2><p>Let&#39;s add a <strong>Status</strong> column that says &quot;Over&quot; when you&#39;ve exceeded the budget and &quot;OK&quot; otherwise. In <strong>E1</strong>, type <code>Status</code>. In <strong>E2</strong>, enter:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=IF(D2 &lt; 0, &quot;Over&quot;, &quot;OK&quot;)</span></span></code></pre></div><p>Copy this formula down to <strong>E7</strong>. Transport should show &quot;Over&quot; since you spent more than budgeted.</p><p>Here&#39;s the completed budget spreadsheet:</p><p><img src="'+o+'" alt="Budget spreadsheet"></p><h2 id="_5-useful-formulas-for-budgets" tabindex="-1">5. Useful Formulas for Budgets <a class="header-anchor" href="#_5-useful-formulas-for-budgets" aria-label="Permalink to &quot;5. Useful Formulas for Budgets&quot;">​</a></h2><p>Here are some formulas you might find useful:</p><h3 id="average-spending" tabindex="-1">Average Spending <a class="header-anchor" href="#average-spending" aria-label="Permalink to &quot;Average Spending&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=AVERAGE(C2:C7)</span></span></code></pre></div><p>Tells you the average actual spending across all categories.</p><h3 id="biggest-expense" tabindex="-1">Biggest Expense <a class="header-anchor" href="#biggest-expense" aria-label="Permalink to &quot;Biggest Expense&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=MAX(C2:C7)</span></span></code></pre></div><p>Finds the largest actual spending amount.</p><h3 id="count-over-budget-items" tabindex="-1">Count Over-Budget Items <a class="header-anchor" href="#count-over-budget-items" aria-label="Permalink to &quot;Count Over-Budget Items&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=COUNTIF(D2:D7, &quot;&lt;0&quot;)</span></span></code></pre></div><p>Counts how many categories went over budget.</p><h3 id="budget-utilization" tabindex="-1">Budget Utilization <a class="header-anchor" href="#budget-utilization" aria-label="Permalink to &quot;Budget Utilization&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=C8/B8*100</span></span></code></pre></div><p>Shows what percentage of your total budget you&#39;ve used.</p><h2 id="what-you-learned" tabindex="-1">What You Learned <a class="header-anchor" href="#what-you-learned" aria-label="Permalink to &quot;What You Learned&quot;">​</a></h2><ul><li><strong>SUM</strong> to total up a column</li><li><strong>Cell references</strong> that adjust when copied (relative references)</li><li><strong>IF</strong> for conditional logic</li><li><strong>AVERAGE</strong>, <strong>MAX</strong>, <strong>COUNTIF</strong> for data analysis</li></ul><h2 id="what-s-next" tabindex="-1">What&#39;s Next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next&quot;">​</a></h2><ul><li><a href="./formulas.html">Formulas Reference</a> — Full list of supported functions</li><li><a href="./collaboration.html">Collaboration &amp; Sharing</a> — Share this budget with others</li></ul>',42)])])}const b=e(n,[["render",r]]);export{g as __pageData,b as default};
